using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    // Breaking change: EF Core 9 throws if Migrate() is called inside a
    // user transaction. Migrations manage their own transactions internally.
    void ApplyMigrations(AppDbContext db)
    {
        var strategy = db.Database.CreateExecutionStrategy();
        strategy.Execute(() =>
        {
            db.Database.Migrate();
        });
    }
}

// Breaking change: EF Core 9 disallows non-deterministic values
// (like DateTime.UtcNow) in HasData seed. Use a fixed value instead.
modelBuilder.Entity<Order>().HasData(
    new Order { Id = 1, CreatedAt = new DateTime(2024, 1, 1, 0, 0, 0, DateTimeKind.Utc) });

