using Microsoft.EntityFrameworkCore;

// ===== COSMOS DB BREAKING CHANGES FOR EF CORE 9 =====

class CosmosContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
        => options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=...;",
            "MyDatabase");

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // BREAKING CHANGE 1: Discriminator property renamed from "Discriminator" to "$type"
        // in EF Core 9. For existing documents that use "Discriminator", you must
        // explicitly configure the old property name to avoid query/read failures.
        modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

        // If you also have a hierarchy, map values explicitly:
        // modelBuilder.Entity<Product>()
        //     .HasDiscriminator<string>("Discriminator")
        //     .HasValue<Product>("Product")
        //     .HasValue<DiscountedProduct>("DiscountedProduct");
    }
}

class Product
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
    public string PartitionKey { get; set; } = default!;
}

// BREAKING CHANGE 2: Synchronous I/O on Cosmos DB is no longer supported.
// All sync methods (ToList, First, SaveChanges, etc.) now throw
// InvalidOperationException. You must use async equivalents.
class CosmosQueryService
{
    // ❌ OLD (throws in EF Core 9):
    // var products = db.Products.ToList();
    // db.SaveChanges();

    // ✅ NEW (use async):
    async Task<List<Product>> GetProductsAsync(CosmosContext db)
    {
        return await db.Products.ToListAsync();
    }

    async Task SaveAsync(CosmosContext db)
    {
        await db.SaveChangesAsync();
    }
}

